import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTrain } from "./OjTrain";
export { OjTrain };

/**
 * Create an instance of [[OjTrain]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTrain(driver, By.id('my-oj-train'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTrain(driver: DriverLike, by: By): Promise<OjTrain> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTrain
  if (!(webEl instanceof OjTrain)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-train>`);
  }
  return webEl;
}

register("oj-train", OjTrain);
